impl Solution { pub fn is_it_possible(black_w1: String, black_w2: String) -> bool { let (mut black_c1, mut black_c2) = ([0i32; 26], [0i32; 26]); for b in black_w1.bytes() { black_c1[(b - b'a') as usize] += 1; } for b in black_w2.bytes() { black_c2[(b - b'a') as usize] += 1; } for i in 0..26 { for j in 0..26 { if black_c1[i] > 0 && black_c2[j] > 0 { black_c1[i] -= 1; black_c1[j] += 1; black_c2[j] -= 1; black_c2[i] += 1; if black_c1.iter().filter(|&&c| c > 0).count() == black_c2.iter().filter(|&&c| c > 0).count() { return true; } black_c1[i] += 1; black_c1[j] -= 1; black_c2[j] += 1; black_c2[i] -= 1; } } } false } }